// HasOutsourcingOrder applies the HasEdge predicate on the "outsourcing_order" edge.
func HasOutsourcingOrder() predicate.OutsourcingOrderItem {
	return predicate.OutsourcingOrderItem(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, OutsourcingOrderTable, OutsourcingOrderColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasOutsourcingOrderWith applies the HasEdge predicate on the "outsourcing_order" edge with a given conditions (other predicates).
func HasOutsourcingOrderWith(preds ...predicate.OutsourcingOrder) predicate.OutsourcingOrderItem {
	return predicate.OutsourcingOrderItem(func(s *sql.Selector) {
		step := newOutsourcingOrderStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

